import socket
from datetime import datetime

# Define constants
HOST = '127.0.0.1'
PORT = 12345

class GameServer:
    def __init__(self):
        self.server_socket = None
        self.player_list = {}
        self.game_state = {}

    def start_server(self):
        # Create UDP server socket
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server_socket.bind((HOST, PORT))

        print(f"Server listening on {HOST}:{PORT}")

    def broadcast(self, message):
        for player in self.player_list:
            if player != message['from']:
                self.send_to_player(player, message)

    def send_to_player(self, ip_address, data):
        try:
            self.server_socket.sendto(data.encode(), (ip_address, PORT))
        except socket.error as e:
            print(f"Error sending to {ip_address}: {e}")

    def handle_request(self, address, request_data):
        query = request_data.decode()
        if query.startswith('status'):
            return self.get_status()

    def get_status(self):
        player_list_str = str(self.player_list)
        game_state_str = str(self.game_state)

        status_message = f"Players: {player_list_str}\nGame State: {game_state_str}"
        return status_message

    def listen_for_requests(self):
        while True:
            request_data, address = self.server_socket.recvfrom(1024)
            response = self.handle_request(address[0], request_data)
            if response is not None:
                print(f"Sending response to {address[0]}")
                self.send_to_player(address[0], response)

def main():
    server = GameServer()
    server.start_server()

    while True:
        # Listen for new connections
        player_address, _ = server.server_socket.recvfrom(1024)
        
        # Get client ID and name
        client_id, _, client_name = player_address.split(":", 2)

        # Add to the list of players
        server.player_list[client_id] = client_name
        
        # Broadcast connection message to all other clients
        msg = {'from': 'server', 'message': f"{client_id} connected"}
        server.broadcast(msg)

if __name__ == "__main__":
    main()